import{_ as t,o,c as e,ag as r}from"./chunks/framework.BZohXCq9.js";const u=JSON.parse('{"title":"我也\\"养虾\\"了，说说大实话","description":"","frontmatter":{},"headers":[],"relativePath":"tools/openclaw/day2.md","filePath":"tools/openclaw/day2.md","lastUpdated":1774068826000}'),s={name:"tools/openclaw/day2.md"};function d(h,a,n,p,l,i){return o(),e("div",null,[...a[0]||(a[0]=[r('<h1 id="我也-养虾-了-说说大实话" tabindex="-1"><a class="header-anchor" href="#我也-养虾-了-说说大实话">¶</a> 我也&quot;养虾&quot;了，说说大实话</h1><blockquote><p>最近社交网络上的热门问候语变成：&quot;今天你养龙虾了吗？&quot;</p></blockquote><h2 id="初体验" tabindex="-1"><a class="header-anchor" href="#初体验">¶</a> 初体验</h2><p>说实话，作为一个每天和电脑打交道的人，我一开始是拒绝的——这年头啥热点都想凑，结果都是一阵风。但耐不住大家都在聊，连我妈的微信群都在转发&quot;龙虾教程&quot;，我寻思要不也试试？</p><p><strong>结果真香了。</strong></p><p>说实话，我原来每天光整理文档、回复邮件、核对数据这些破事儿，就能耗掉小半天。装了&quot;龙虾&quot;之后，这些破事它真的帮我干了。虽然没网上传的那么神——什么&quot;一键外包给老板&quot;，那是网上玩梗——但确实让我能腾出手来做点正事。</p><h2 id="踩坑实录" tabindex="-1"><a class="header-anchor" href="#踩坑实录">¶</a> 踩坑实录</h2><p>不过踩坑也是真的踩了。</p><h3 id="第一个坑-以为装上就能用" tabindex="-1"><a class="header-anchor" href="#第一个坑-以为装上就能用">¶</a> 第一个坑：以为装上就能用</h3><p>拉倒吧，这东西真不是给小白准备的。什么命令行、API密钥、管理员权限...我折腾了一下午才跑起来，比装Windows系统都费劲。网上那些&quot;五分钟上手&quot;的视频，看看就好。</p><h3 id="第二个坑-隐私那事儿" tabindex="-1"><a class="header-anchor" href="#第二个坑-隐私那事儿">¶</a> 第二个坑：隐私那事儿</h3><p>刚开始我也没当回事，后来看到有人说他浏览器存的密码被&quot;看&quot;光了脊背一凉。现在我都小心翼翼，能不给的权限尽量不给。</p><h3 id="第三个坑-它真的会-失控" tabindex="-1"><a class="header-anchor" href="#第三个坑-它真的会-失控">¶</a> 第三个坑：它真的会&quot;失控&quot;</h3><p>有次我让它帮我删一批旧邮件，好家伙，它删上瘾了，把我刚收到的也差点清了...得亏反应快拦住了。</p><h2 id="总结" tabindex="-1"><a class="header-anchor" href="#总结">¶</a> 总结</h2><ul><li>✅ 确实能干活，效率有提升</li><li>❌ 门槛比想象中高，别信那些&quot;神器&quot;</li><li>⚠️ 隐私问题要注意，能不用就不用的场景别硬用</li><li>🤔 别焦虑，不是所有人都必须&quot;养虾&quot;</li></ul><p>总的来说，这东西有点像——给你一台专业相机的散件，你会用了能拍大片，不会用就是一堆废铁。</p><p>你问我还会继续用吗？用还是会用的，但不会把它吹上天，也不会一棒子打死。就酱。</p><hr><p><strong>【话题互动】</strong>：你&quot;养虾&quot;了吗？踩过什么坑？评论区聊聊</p>',20)])])}const q=t(s,[["render",d]]);export{u as __pageData,q as default};
